def evaluate(ctx):
    count = 0
    for event in ctx["history"]:
        if event.get("session") == ctx["request"]["metadata"]["session"] and "rm -rf" in event.get("text", ""):
            count += 1
    if count >= 1:
        return {"action": "block", "reason": "dangerous history"}
    return {"action": "allow", "reason": "no match"}

def evaluate(ctx):
    for event in ctx["structured_output"].get("guard_events", []):
        if event.get("guard_type") == "json_syntax":
            return {"action": "retry", "reason": "repair structured json"}
    return {"action": "allow", "reason": "no guard"}

def evaluate(ctx):
    if ctx["request"]["estimated_tokens"] > 1000:
        return {"action": "switch_model", "model": "ingary/large-context", "reason": "large prompt"}
    return {"action": "allow", "reason": "small prompt"}
